SELECT COUNT(study_id) AS number_of_studies
FROM studies
WHERE state_id = (SELECT state_id FROM states WHERE abbreviation = 'CA');

SELECT principal_investigator, COUNT(DISTINCT study_id) AS number_of_studies
FROM studies
GROUP BY principal_investigator;

SELECT COUNT(*) AS number_of_studies
FROM studies
WHERE principal_investigator = 'Dr. Jane Smith';

SELECT s.study_name, dut.usage_type
FROM studies s
INNER JOIN data_usage_types dut ON s.data_usage_id = dut.usage_id;

SELECT COUNT(study_id) AS total_studies_funded_by_autism_speaks
FROM funding_sources
WHERE funding_agency = 'Autism Speaks';

SELECT COUNT(DISTINCT study_id) AS number_of_studies
FROM publications
WHERE journal = 'Journal of Autism Research' AND year BETWEEN 2020 AND 2023;
